import{_ as i,o as t,c as a,a0 as o}from"./chunks/framework.CWk8AOcY.js";const u=JSON.parse('{"title":"Backing up and resetting","description":"","frontmatter":{},"headers":[],"relativePath":"articles/backing-up-and-resetting.md","filePath":"articles/backing-up-and-resetting.md"}'),r={name:"articles/backing-up-and-resetting.md"};function n(s,e,l,d,c,h){return t(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="backing-up-and-resetting" tabindex="-1">Backing up and resetting <a class="header-anchor" href="#backing-up-and-resetting" aria-label="Permalink to &quot;Backing up and resetting&quot;">​</a></h1><p>This guide covers backup, migration, reset, and common troubleshooting tasks for Robocode Tank Royale user data.</p><h2 id="backing-up-your-configuration" tabindex="-1">Backing up your configuration <a class="header-anchor" href="#backing-up-your-configuration" aria-label="Permalink to &quot;Backing up your configuration&quot;">​</a></h2><ol><li>Locate your user data directory</li><li>Copy the entire directory to a backup location</li><li>Store the backup somewhere safe</li></ol><p>For the exact paths, see <a href="./user-data-locations.html">User data locations</a>.</p><h2 id="migrating-to-a-new-computer" tabindex="-1">Migrating to a new computer <a class="header-anchor" href="#migrating-to-a-new-computer" aria-label="Permalink to &quot;Migrating to a new computer&quot;">​</a></h2><ol><li>Install Robocode Tank Royale on the new computer</li><li>Locate the user data directory on the new computer</li><li>Copy your backed-up configuration files into that directory</li><li>Replace existing files if prompted</li><li>Launch the GUI</li></ol><p>Bot directories and bot files are not stored in the user data directory, so you must copy or download those separately and then reconfigure <strong>Bot Root Directories</strong>.</p><h2 id="resetting-to-defaults" tabindex="-1">Resetting to defaults <a class="header-anchor" href="#resetting-to-defaults" aria-label="Permalink to &quot;Resetting to defaults&quot;">​</a></h2><ol><li>Close the GUI completely</li><li>Locate your user data directory</li><li>Delete or rename the directory</li><li>Launch the GUI again</li></ol><p>A new directory with default settings is created automatically.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="cannot-find-the-user-data-directory" tabindex="-1">Cannot find the user data directory <a class="header-anchor" href="#cannot-find-the-user-data-directory" aria-label="Permalink to &quot;Cannot find the user data directory&quot;">​</a></h3><p>If you cannot locate the directory:</p><ol><li>Launch the GUI</li><li>Open <strong>Help → About</strong></li><li>Check the runtime details and logs for the path in use</li></ol><p>Or verify the environment-based location directly:</p><p><strong>Windows</strong></p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">echo </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LOCALAPPDATA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\Robocode Tank Royale</span></span></code></pre></div><p><strong>macOS and Linux</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Application</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Support/Robocode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Tank</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Royale</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/robocode-tank-royale</span></span></code></pre></div><h3 id="configuration-is-not-being-saved" tabindex="-1">Configuration is not being saved <a class="header-anchor" href="#configuration-is-not-being-saved" aria-label="Permalink to &quot;Configuration is not being saved&quot;">​</a></h3><p>Check that:</p><ol><li>you have write permission to the user data directory</li><li>the directory is not read-only</li><li>the GUI is not running in a protected location</li></ol><h3 id="corrupted-configuration-files" tabindex="-1">Corrupted configuration files <a class="header-anchor" href="#corrupted-configuration-files" aria-label="Permalink to &quot;Corrupted configuration files&quot;">​</a></h3><p>If a <code>.properties</code> file becomes corrupted:</p><ol><li>Close the GUI</li><li>Delete or rename the problematic file</li><li>Restart the GUI</li><li>Reconfigure the affected settings</li></ol><h3 id="migrating-old-recordings" tabindex="-1">Migrating old recordings <a class="header-anchor" href="#migrating-old-recordings" aria-label="Permalink to &quot;Migrating old recordings&quot;">​</a></h3><p>If you upgraded from version 0.34.1 or earlier, you might still have recordings in the old project-level <code>recordings</code> directory.</p><p>To migrate them:</p><ol><li>Locate the old <code>recordings</code> directory in your Robocode installation folder</li><li>Copy all <code>.battle.gz</code> files</li><li>Paste them into the recordings directory under the user data directory</li></ol>`,30)])])}const g=i(r,[["render",n]]);export{u as __pageData,g as default};
